import React from 'react';
import { getRiskColor, getStatusStyle } from '../utils/helpers';
import { AlertTriangle, TrendingUp, Shield, Eye } from 'lucide-react';

// ── Spinner ────────────────────────────────────────────────────
export const Spinner = ({ size = 'md', className = '' }) => {
  const s = { sm: 'h-4 w-4', md: 'h-6 w-6', lg: 'h-10 w-10' }[size];
  return (
    <div className={`${s} border-2 border-brand-200 border-t-brand-600 rounded-full animate-spin ${className}`} />
  );
};

// ── LoadingScreen ──────────────────────────────────────────────
export const LoadingScreen = ({ message = 'Loading...' }) => (
  <div className="min-h-screen flex flex-col items-center justify-center gap-4 bg-slate-50">
    <Spinner size="lg" />
    <p className="text-slate-500 text-sm font-medium">{message}</p>
  </div>
);

// ── StatusBadge ────────────────────────────────────────────────
export const StatusBadge = ({ status }) => {
  const st = getStatusStyle(status);
  return (
    <span className={`badge ${st.badge}`}>
      <span className={`w-1.5 h-1.5 rounded-full ${st.dot}`} />
      {st.label}
    </span>
  );
};

// ── RiskBadge ──────────────────────────────────────────────────
export const RiskBadge = ({ score }) => {
  const r = getRiskColor(score);
  return (
    <span className={`badge ${r.bg} ${r.text}`}>
      {r.label} {Math.round(score * 100)}%
    </span>
  );
};

// ── RiskBar ────────────────────────────────────────────────────
export const RiskBar = ({ score, showLabel = true }) => {
  const r = getRiskColor(score);
  const pct = Math.round(score * 100);
  return (
    <div className="space-y-1">
      {showLabel && (
        <div className="flex justify-between text-xs">
          <span className={`font-semibold ${r.text}`}>{r.label}</span>
          <span className="text-slate-500 font-mono">{pct}%</span>
        </div>
      )}
      <div className="h-1.5 w-full bg-slate-100 rounded-full overflow-hidden">
        <div
          className={`h-full rounded-full transition-all duration-700 ${r.bar}`}
          style={{ width: `${pct}%` }}
        />
      </div>
    </div>
  );
};

// ── Alert ──────────────────────────────────────────────────────
export const Alert = ({ type = 'error', message, onClose }) => {
  if (!message) return null;
  const styles = {
    error: 'bg-red-50 border-red-200 text-red-700',
    success: 'bg-emerald-50 border-emerald-200 text-emerald-700',
    warning: 'bg-amber-50 border-amber-200 text-amber-700',
    info: 'bg-blue-50 border-blue-200 text-blue-700',
  };
  return (
    <div className={`flex items-start gap-3 px-4 py-3 rounded-xl border text-sm animate-fade-in ${styles[type]}`}>
      <AlertTriangle className="w-4 h-4 mt-0.5 flex-shrink-0" />
      <span className="flex-1">{message}</span>
      {onClose && (
        <button onClick={onClose} className="opacity-60 hover:opacity-100 transition-opacity">✕</button>
      )}
    </div>
  );
};

// ── Card ───────────────────────────────────────────────────────
export const Card = ({ children, className = '', hover = false }) => (
  <div className={`bg-white border border-slate-200 rounded-2xl ${hover ? 'card-hover cursor-pointer' : ''} ${className}`}>
    {children}
  </div>
);

// ── StatCard ───────────────────────────────────────────────────
export const StatCard = ({ icon: Icon, label, value, sub, color = 'brand', trend }) => {
  const colors = {
    brand: 'bg-indigo-50 text-indigo-600',
    blue: 'bg-blue-50 text-blue-600',
    amber: 'bg-amber-50 text-amber-600',
    green: 'bg-emerald-50 text-emerald-600',
    red: 'bg-red-50 text-red-600',
    purple: 'bg-purple-50 text-purple-600',
  };
  return (
    <Card hover className="p-5">
      <div className="flex items-start justify-between mb-3">
        <div className={`p-2.5 rounded-xl ${colors[color]}`}>
          <Icon className="w-5 h-5" />
        </div>
        {trend !== undefined && (
          <span className={`text-xs font-medium ${trend >= 0 ? 'text-emerald-600' : 'text-red-500'}`}>
            <TrendingUp className="w-3 h-3 inline mr-0.5" />
            {Math.abs(trend)}%
          </span>
        )}
      </div>
      <div className="text-2xl font-bold font-display text-slate-900">{value}</div>
      <div className="text-sm text-slate-500 mt-0.5">{label}</div>
      {sub && <div className="text-xs text-slate-400 mt-1">{sub}</div>}
    </Card>
  );
};

// ── Table ──────────────────────────────────────────────────────
export const Table = ({ headers, children, empty = 'No records found.' }) => (
  <div className="overflow-x-auto">
    <table className="w-full text-sm">
      <thead>
        <tr className="border-b border-slate-100">
          {headers.map((h, i) => (
            <th key={i} className="text-left px-4 py-3 text-xs font-semibold text-slate-400 uppercase tracking-wider whitespace-nowrap">
              {h}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {children || (
          <tr>
            <td colSpan={headers.length} className="text-center py-12 text-slate-400">{empty}</td>
          </tr>
        )}
      </tbody>
    </table>
  </div>
);

// ── Button ─────────────────────────────────────────────────────
export const Button = ({
  children, onClick, type = 'button', variant = 'primary',
  size = 'md', loading = false, disabled = false, className = '', icon: Icon,
}) => {
  const base = 'inline-flex items-center justify-center gap-2 font-semibold rounded-xl transition-all duration-150 focus:outline-none focus:ring-2 focus:ring-offset-1';
  const variants = {
    primary: 'bg-brand-600 hover:bg-brand-700 text-white focus:ring-brand-500 shadow-sm',
    secondary: 'bg-white hover:bg-slate-50 text-slate-700 border border-slate-200 focus:ring-slate-300',
    danger: 'bg-red-600 hover:bg-red-700 text-white focus:ring-red-500',
    success: 'bg-emerald-600 hover:bg-emerald-700 text-white focus:ring-emerald-500',
    warning: 'bg-amber-500 hover:bg-amber-600 text-white focus:ring-amber-400',
    ghost: 'text-slate-600 hover:bg-slate-100 focus:ring-slate-300',
  };
  const sizes = {
    sm: 'px-3 py-1.5 text-xs',
    md: 'px-4 py-2 text-sm',
    lg: 'px-6 py-3 text-base',
  };
  return (
    <button
      type={type}
      onClick={onClick}
      disabled={disabled || loading}
      className={`${base} ${variants[variant]} ${sizes[size]} ${(disabled || loading) ? 'opacity-60 cursor-not-allowed' : ''} ${className}`}
    >
      {loading ? <Spinner size="sm" /> : Icon && <Icon className="w-4 h-4" />}
      {children}
    </button>
  );
};

// ── FormField ──────────────────────────────────────────────────
export const FormField = ({ label, error, required, children, hint }) => (
  <div className="space-y-1.5">
    {label && (
      <label className="block text-sm font-medium text-slate-700">
        {label} {required && <span className="text-red-500">*</span>}
      </label>
    )}
    {children}
    {hint && !error && <p className="text-xs text-slate-400">{hint}</p>}
    {error && <p className="text-xs text-red-600 flex items-center gap-1"><AlertTriangle className="w-3 h-3" />{error}</p>}
  </div>
);

export const Input = ({ className = '', error, ...props }) => (
  <input
    className={`w-full px-3.5 py-2.5 rounded-xl border text-sm transition-colors
      ${error ? 'border-red-400 bg-red-50' : 'border-slate-200 bg-white hover:border-slate-300 focus:border-brand-400'}
      ${className}`}
    {...props}
  />
);

export const Select = ({ className = '', error, children, ...props }) => (
  <select
    className={`w-full px-3.5 py-2.5 rounded-xl border text-sm bg-white transition-colors
      ${error ? 'border-red-400' : 'border-slate-200 hover:border-slate-300 focus:border-brand-400'}
      ${className}`}
    {...props}
  >
    {children}
  </select>
);

export const Textarea = ({ className = '', error, ...props }) => (
  <textarea
    className={`w-full px-3.5 py-2.5 rounded-xl border text-sm transition-colors resize-none
      ${error ? 'border-red-400 bg-red-50' : 'border-slate-200 bg-white hover:border-slate-300 focus:border-brand-400'}
      ${className}`}
    {...props}
  />
);

// ── MLScorePanel ───────────────────────────────────────────────
export const MLScorePanel = ({ data }) => {
  const scores = [
    { label: 'Fraud Probability', value: data.fraud_probability, icon: AlertTriangle },
    { label: 'Anomaly Score', value: data.anomaly_score, icon: TrendingUp },
    { label: 'Image Authenticity Risk', value: data.image_authenticity_score, icon: Eye },
    { label: 'Overall Risk', value: data.risk_score, icon: Shield },
  ];
  return (
    <div className="space-y-4">
      {scores.map(({ label, value, icon: Icon }) => {
        const r = getRiskColor(value);
        return (
          <div key={label} className="flex items-center gap-3">
            <div className={`p-1.5 rounded-lg ${r.bg}`}>
              <Icon className={`w-3.5 h-3.5 ${r.text}`} />
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex justify-between items-center mb-1">
                <span className="text-xs font-medium text-slate-600 truncate">{label}</span>
                <span className={`text-xs font-bold font-mono ${r.text}`}>{(value * 100).toFixed(1)}%</span>
              </div>
              <div className="h-1.5 bg-slate-100 rounded-full overflow-hidden">
                <div className={`h-full rounded-full ${r.bar}`} style={{ width: `${value * 100}%`, transition: 'width 1s ease' }} />
              </div>
            </div>
          </div>
        );
      })}
    </div>
  );
};
